INSERT INTO `questions` (`question_number`, `display_number`, `strategy_number`, `strategy_name`, `question_text`, `question_type`, `sort_order`, `is_active`) VALUES
(1, 1, 1, 'ยุทธศาสตร์ที่ 1: ยกระดับทักษะภาษาไทยและพหุภาษาสู่สากล', 'ร้อยละผู้เรียนได้รับการพัฒนาทักษะภาษา อย่างน้อย 3 ภาษา (มลายู, อังกฤษ, จีน, อาหรับ, ญี่ปุ่น, เกาหลี หรือภาษาอื่นๆ ตามความสนใจ)', 'percentage', 1, 1),
(2, 2, 1, 'ยุทธศาสตร์ที่ 1: ยกระดับทักษะภาษาไทยและพหุภาษาสู่สากล', 'ร้อยละของสถานศึกษาได้รับการนิเทศ ติดตามการอ่านการเขียนภาษาไทย โดยเครือข่ายของแต่ละสังกัดในจังหวัดปัตตานี', 'yes_no', 2, 1),
(3, 3, 3, 'ยุทธศาสตร์ที่ 3: สร้างโอกาส ความเสมอภาคและความเท่าเทียมทางการศึกษาคนทุกช่วงวัย', 'ร้อยละของผู้เรียนได้รับการพัฒนาตามความสามารถตามความถนัดด้านพหุปัญญา', 'percentage', 3, 1),
(4, 4, 4, 'ยุทธศาสตร์ที่ 4: ค้นหาความถนัด พัฒนาศักยภาพ และสร้างอัตลักษณ์ เพื่ออนาคตเด็กปัตตานี', 'ร้อยละของผู้เรียนที่ผ่านการประเมินสุขภาวะที่ดีตามเกณฑ์มาตรฐาน', 'percentage', 4, 1),
(5, 5, 5, 'ยุทธศาสตร์ที่ 5: ปลูกฝังคุณธรรม จริยธรรม ความรักชาติ ศาสน์ กษัตริย์ และค่านิยมพหุวัฒนธรรม สู่การเป็นพลเมืองโลก', 'ร้อยละของสถานศึกษาที่มีส่วนร่วมกับภาคีเครือข่ายในการจัดกิจกรรมส่งเสริมการรักชาติ ศาสน์ กษัตริย์', 'yes_no', 5, 1),
(6, 6, 5, 'ยุทธศาสตร์ที่ 5: ปลูกฝังคุณธรรม จริยธรรม ความรักชาติ ศาสน์ กษัตริย์ และค่านิยมพหุวัฒนธรรม สู่การเป็นพลเมืองโลก', 'ร้อยละของนักเรียนที่ได้รับรางวัลด้านคุณธรรม จริยธรรมและความเป็นพลเมือง', 'percentage', 6, 1),
(7, 7, 6, 'ยุทธศาสตร์ที่ 6: ส่งเสริมการศึกษาเพื่ออาชีพ สร้างผู้ประกอบการรุ่นใหม่ วางเส้นทางอนาคตที่มั่นคง เพื่อเศรษฐกิจปัตตานียั่งยืน', 'ร้อยละผู้เรียนที่ได้รับการแนะแนวการศึกษา/อาชีพ/ส่วนตัว/สังคม อย่างน้อยปีละ 1 ครั้ง', 'percentage', 7, 1),
(8, 8, 6, 'ยุทธศาสตร์ที่ 6: ส่งเสริมการศึกษาเพื่ออาชีพ สร้างผู้ประกอบการรุ่นใหม่ วางเส้นทางอนาคตที่มั่นคง เพื่อเศรษฐกิจปัตตานียั่งยืน', 'อัตราการเพิ่มขึ้นของเครือข่ายความร่วมมือ (MOU) ระหว่างสถานศึกษากับสถานประกอบการ ชุมชน และหน่วยงานภาคเอกชน', 'percentage', 8, 1),
(9, 9, 6, 'ยุทธศาสตร์ที่ 6: ส่งเสริมการศึกษาเพื่ออาชีพ สร้างผู้ประกอบการรุ่นใหม่ วางเส้นทางอนาคตที่มั่นคง เพื่อเศรษฐกิจปัตตานียั่งยืน', 'ร้อยละผู้เรียน (ม.ปลาย/อาชีวศึกษา/อนุปริญญา) ที่มีรายได้ระหว่างเรียน', 'percentage', 9, 1),
(10, 10, 8, 'ยุทธศาสตร์ที่ 8: การบริหารจัดการที่เน้นการมีส่วนร่วม โปร่งใส ทันสมัย และมุ่งผลสัมฤทธิ์', 'ร้อยละของหน่วยงานทางการศึกษาที่มีผลการประเมินคุณธรรมความโปร่งใส (ITA) ในระดับ AA', 'rating', 12, 1),
(11, 11, 7, 'ยุทธศาสตร์ที่ 7: ยกระดับ ปรับโฉม และขยายพื้นที่นวัตกรรมการศึกษา จังหวัดปัตตานี', 'จำนวนหุ้นส่วนความร่วมมือทั้งภาครัฐ เอกชน และประชาสังคม', 'count', 10, 1),
(12, 12, 7, 'ยุทธศาสตร์ที่ 7: ยกระดับ ปรับโฉม และขยายพื้นที่นวัตกรรมการศึกษา จังหวัดปัตตานี', 'จำนวนนวัตกรรมที่ใช้จริง', 'count', 11, 1);
